def to_info_dict(self) -> dict[str, t.Any]:
    info_dict = super().to_info_dict()
    info_dict.update(
        help=self.help,
        prompt=self.prompt,
        is_flag=self.is_flag,
        flag_value=self.flag_value,
        count=self.count,
        hidden=self.hidden,
    )
    return info_dict

def get_error_hint(self, ctx: Context) -> str:
    result = super().get_error_hint(ctx)
    if self.show_envvar:
        result += f" (env var: '{self.envvar}')"
    return result

def _parse_decls(
    self, decls: cabc.Sequence[str], expose_value: bool
) -> tuple[str | None, list[str], list[str]]:
    opts = []
    secondary_opts = []
    name = None
    possible_names = []

    for decl in decls:
        if decl.isidentifier():
            if name is not None:
                raise TypeError(f"Name '{name}' defined twice")
            name = decl
        else:
            split_char = ";" if decl[:1] == "/" else "/"
            if split_char in decl:
                first, second = decl.split(split_char, 1)
                first = first.rstrip()
                if first:
                    possible_names.append(_split_opt(first))
                    opts.append(first)
                second = second.lstrip()
                if second:
                    secondary_opts.append(second.lstrip())
                if first == second:
                    raise ValueError(
                        f"Boolean option {decl!r} cannot use the"
                        " same flag for true/false."
                    )
            else:
                possible_names.append(_split_opt(decl))
                opts.append(decl)

    if name is None and possible_names:
        possible_names.sort(key=lambda x: -len(x[0]))  # group long options first
        name = possible_names[0][1].replace("-", "_").lower()
        if not name.isidentifier():
            name = None

    if name is None:
        if not expose_value:
            return None, opts, secondary_opts
        raise TypeError(
            f"Could not determine name for option with declarations {decls!r}"
        )

    if not opts and not secondary_opts:
        raise TypeError(
            f"No options defined but a name was passed ({name})."
            " Did you mean to declare an argument instead? Did"
            f" you mean to pass '--{name}'?"
        )

    return name, opts, secondary_opts

def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    if self.multiple:
        action = "append"
    elif self.count:
        action = "count"
    else:
        action = "store"

    if self.is_flag:
        action = f"{action}_const"

        if self.is_bool_flag and self.secondary_opts:
            parser.add_option(
                obj=self, opts=self.opts, dest=self.name, action=action, const=True
            )
            parser.add_option(
                obj=self,
                opts=self.secondary_opts,
                dest=self.name,
                action=action,
                const=False,
            )
        else:
            parser.add_option(
                obj=self,
                opts=self.opts,
                dest=self.name,
                action=action,
                const=self.flag_value,
            )
    else:
        parser.add_option(
            obj=self,
            opts=self.opts,
            dest=self.name,
            action=action,
            nargs=self.nargs,
        )

def get_help_record(self, ctx: Context) -> tuple[str, str] | None:
    if self.hidden:
        return None

    any_prefix_is_slash = False

    def _write_opts(opts: cabc.Sequence[str]) -> str:
        nonlocal any_prefix_is_slash

        rv, any_slashes = join_options(opts)

        if any_slashes:
            any_prefix_is_slash = True

        if not self.is_flag and not self.count:
            rv += f" {self.make_metavar(ctx=ctx)}"

        return rv

    rv = [_write_opts(self.opts)]

    if self.secondary_opts:
        rv.append(_write_opts(self.secondary_opts))

    help = self.help or ""

    extra = self.get_help_extra(ctx)
    extra_items = []
    if "envvars" in extra:
        extra_items.append(
            _("env var: {var}").format(var=", ".join(extra["envvars"]))
        )
    if "default" in extra:
        extra_items.append(_("default: {default}").format(default=extra["default"]))
    if "range" in extra:
        extra_items.append(extra["range"])
    if "required" in extra:
        extra_items.append(_(extra["required"]))

    if extra_items:
        extra_str = "; ".join(extra_items)
        help = f"{help}  [{extra_str}]" if help else f"[{extra_str}]"

    return ("; " if any_prefix_is_slash else " / ").join(rv), help

def get_help_extra(self, ctx: Context) -> types.OptionHelpExtra:
    extra: types.OptionHelpExtra = {}

    if self.show_envvar:
        envvar = self.envvar

        if envvar is None:
            if (
                self.allow_from_autoenv
                and ctx.auto_envvar_prefix is not None
                and self.name is not None
            ):
                envvar = f"{ctx.auto_envvar_prefix}_{self.name.upper()}"

        if envvar is not None:
            if isinstance(envvar, str):
                extra["envvars"] = (envvar,)
            else:
                extra["envvars"] = tuple(str(d) for d in envvar)

    # Temporarily enable resilient parsing to avoid type casting
    # failing for the default. Might be possible to extend this to
    # help formatting in general.
    resilient = ctx.resilient_parsing
    ctx.resilient_parsing = True

    try:
        default_value = self.get_default(ctx, call=False)
    finally:
        ctx.resilient_parsing = resilient

    show_default = False
    show_default_is_str = False

    if self.show_default is not None:
        if isinstance(self.show_default, str):
            show_default_is_str = show_default = True
        else:
            show_default = self.show_default
    elif ctx.show_default is not None:
        show_default = ctx.show_default

    if show_default_is_str or (show_default and (default_value is not None)):
        if show_default_is_str:
            default_string = f"({self.show_default})"
        elif isinstance(default_value, (list, tuple)):
            default_string = ", ".join(str(d) for d in default_value)
        elif inspect.isfunction(default_value):
            default_string = _("(dynamic)")
        elif self.is_bool_flag and self.secondary_opts:
            # For boolean flags that have distinct True/False opts,
            # use the opt without prefix instead of the value.
            default_string = _split_opt(
                (self.opts if default_value else self.secondary_opts)[0]
            )[1]
        elif self.is_bool_flag and not self.secondary_opts and not default_value:
            default_string = ""
        elif default_value == "":
            default_string = '""'
        else:
            default_string = str(default_value)

def get_default(
    self, ctx: Context, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload
def get_default(
    self, ctx: Context, call: bool = ...
) -> t.Any | t.Callable[[], t.Any] | None: ...

def get_default(
    self, ctx: Context, call: bool = True
) -> t.Any | t.Callable[[], t.Any] | None:
    """Get the default for the parameter. Tries
    :meth:`Context.lookup_default` first, then the local default.

    :param ctx: Current context.
    :param call: If the default is a callable, call it. Disable to
        return the callable instead.

    .. versionchanged:: 8.0.2
        Type casting is no longer performed when getting a default.

    .. versionchanged:: 8.0.1
        Type casting can fail in resilient parsing mode. Invalid
        defaults will not prevent showing help text.

    .. versionchanged:: 8.0
        Looks at ``ctx.default_map`` first.

    .. versionchanged:: 8.0
        Added the ``call`` parameter.
    """
    value = ctx.lookup_default(self.name, call=False)  # type: ignore

    if value is None:
        value = self.default

    if call and callable(value):
        value = value()

    return value

def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    raise NotImplementedError()

def consume_value(
    self, ctx: Context, opts: cabc.Mapping[str, t.Any]
) -> tuple[t.Any, ParameterSource]:
    value = opts.get(self.name)  # type: ignore
    source = ParameterSource.COMMANDLINE

    if value is None:
        value = self.value_from_envvar(ctx)
        source = ParameterSource.ENVIRONMENT

    if value is None:
        value = ctx.lookup_default(self.name)  # type: ignore
        source = ParameterSource.DEFAULT_MAP

    if value is None:
        value = self.get_default(ctx)
        source = ParameterSource.DEFAULT

    return value, source

def type_cast_value(self, ctx: Context, value: t.Any) -> t.Any:
    """Convert and validate a value against the option's
    :attr:`type`, :attr:`multiple`, and :attr:`nargs`.
    """
    if value is None:
        return () if self.multiple or self.nargs == -1 else None

    def check_iter(value: t.Any) -> cabc.Iterator[t.Any]:
        try:
            return _check_iter(value)
        except TypeError:
            # This should only happen when passing in args manually,
            # the parser should construct an iterable when parsing
            # the command line.
            raise BadParameter(
                _("Value must be an iterable."), ctx=ctx, param=self
            ) from None

    if self.nargs == 1 or self.type.is_composite:

        def convert(value: t.Any) -> t.Any:
            return self.type(value, param=self, ctx=ctx)

    elif self.nargs == -1:

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            return tuple(self.type(x, self, ctx) for x in check_iter(value))

    else:  # nargs > 1

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            value = tuple(check_iter(value))

            if len(value) != self.nargs:
                raise BadParameter(
                    ngettext(
                        "Takes {nargs} values but 1 was given.",
                        "Takes {nargs} values but {len} were given.",
                        len(value),
                    ).format(nargs=self.nargs, len=len(value)),
                    ctx=ctx,
                    param=self,
                )

            return tuple(self.type(x, self, ctx) for x in value)

    if self.multiple:
        return tuple(convert(x) for x in check_iter(value))

    return convert(value)

def value_is_missing(self, value: t.Any) -> bool:
    if value is None:
        return True

    if (self.nargs != 1 or self.multiple) and value == ():
        return True

    return False

def process_value(self, ctx: Context, value: t.Any) -> t.Any:
    value = self.type_cast_value(ctx, value)

    if self.required and self.value_is_missing(value):
        raise MissingParameter(ctx=ctx, param=self)

    if self.callback is not None:
        value = self.callback(ctx, self, value)

    return value

def resolve_envvar_value(self, ctx: Context) -> str | None:
    if self.envvar is None:
        return None

    if isinstance(self.envvar, str):
        rv = os.environ.get(self.envvar)

        if rv:
            return rv
    else:
        for envvar in self.envvar:
            rv = os.environ.get(envvar)

            if rv:
                return rv

    return None

def value_from_envvar(self, ctx: Context) -> t.Any | None:
    rv: t.Any | None = self.resolve_envvar_value(ctx)

    if rv is not None and self.nargs != 1:
        rv = self.type.split_envvar_value(rv)

    return rv

def handle_parse_result(
    self, ctx: Context, opts: cabc.Mapping[str, t.Any], args: list[str]
) -> tuple[t.Any, list[str]]:
    with augment_usage_errors(ctx, param=self):
        value, source = self.consume_value(ctx, opts)

        if (
            self.deprecated
            and value is not None
            and source
            not in (
                ParameterSource.DEFAULT,
                ParameterSource.DEFAULT_MAP,

                    ParameterSource.DEFAULT_MAP,
                )
            ):
                extra_message = (
                    f" {self.deprecated}" if isinstance(self.deprecated, str) else ""
                )
                message = _(
                    "DeprecationWarning: The {param_type} {name!r} is deprecated."
                    "{extra_message}"
                ).format(
                    param_type=self.param_type_name,
                    name=self.human_readable_name,
                    extra_message=extra_message,
                )
                echo(style(message, fg="red"), err=True)

            ctx.set_parameter_source(self.name, source)  # type: ignore

            try:
                value = self.process_value(ctx, value)
            except Exception:
                if not ctx.resilient_parsing:
                    raise

                value = None

        if self.expose_value:
            ctx.params[self.name] = value  # type: ignore

        return value, args

    def get_help_record(self, ctx: Context) -> tuple[str, str] | None:
        pass

    def get_usage_pieces(self, ctx: Context) -> list[str]:
        return []

    def get_error_hint(self, ctx: Context) -> str:
        """Get a stringified version of the param for use in error messages to
        indicate which param caused the error.
        """
        hint_list = self.opts or [self.human_readable_name]
        return " / ".join(f"'{x}'" for x in hint_list)

    def shell_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
        """Return a list of completions for the incomplete value. If a
        ``shell_complete`` function was given during init, it is used.
        Otherwise, the :attr:`type`
        :meth:`~click.types.ParamType.shell_complete` function is used.

        :param ctx: Invocation context for this command.
        :param incomplete: Value being completed. May be empty.

        .. versionadded:: 8.0
        """
        if self._custom_shell_complete is not None:
            results = self._custom_shell_complete(ctx, self, incomplete)

            if results and isinstance(results[0], str):
                from click.shell_completion import CompletionItem

                results = [CompletionItem(c) for c in results]

            return t.cast("list[CompletionItem]", results)

        return self.type.shell_complete(ctx, self, incomplete)


class Option(Parameter):
    """Options are usually optional values on the command line and

def make_parser(self, ctx: Context) -> _OptionParser:
    """Creates the underlying option parser for this command."""
    parser = _OptionParser(ctx)
    for param in self.get_params(ctx):
        param.add_to_parser(parser, ctx)
    return parser

def get_help(self, ctx: Context) -> str:
    """Formats the help into a string and returns it.

    Calls :meth:`format_help` internally.
    """
    formatter = ctx.make_formatter()
    self.format_help(ctx, formatter)
    return formatter.getvalue().rstrip("\n")

def get_short_help_str(self, limit: int = 45) -> str:
    """Gets short help for the command or makes it by shortening the
    long help string.
    """
    if self.short_help:
        text = inspect.cleandoc(self.short_help)
    elif self.help:
        text = make_default_short_help(self.help, limit)
    else:
        text = ""

    if self.deprecated:
        deprecated_message = (
            f"(DEPRECATED: {self.deprecated})"
            if isinstance(self.deprecated, str)
            else "(DEPRECATED)"
        )
        text = _("{text} {deprecated_message}").format(
            text=text, deprecated_message=deprecated_message
        )

    return text.strip()

def format_help(self, ctx: Context, formatter: HelpFormatter) -> None:
    """Writes the help into the formatter if it exists.

    This is a low-level method called by :meth:`get_help`.

    This calls the following methods:

    -   :meth:`format_usage`
    -   :meth:`format_help_text`
    -   :meth:`format_options`
    -   :meth:`format_epilog`
    """
    self.format_usage(ctx, formatter)
    self.format_help_text(ctx, formatter)
    self.format_options(ctx, formatter)
    self.format_epilog(ctx, formatter)

def format_help_text(self, ctx: Context, formatter: HelpFormatter) -> None:
    """Writes the help text to the formatter if it exists."""
    if self.help is not None:
        # truncate the help text to the first form feed
        text = inspect.cleandoc(self.help).partition("\f")[0]
    else:
        text = ""

    if self.deprecated:
        deprecated_message = (
            f"(DEPRECATED: {self.deprecated})"
            if isinstance(self.deprecated, str)
            else "(DEPRECATED)"
        )
        text = _("{text} {deprecated_message}").format(
            text=text, deprecated_message=deprecated_message
        )

    if text:
        formatter.write_paragraph()

        with formatter.indentation():
            formatter.write_text(text)

def format_options(self, ctx: Context, formatter: HelpFormatter) -> None:
    """Writes all the options into the formatter if they exist."""
    opts = []
    for param in self.get_params(ctx):
        rv = param.get_help_record(ctx)
        if rv is not None:
            opts.append(rv)

    if opts:
        with formatter.section(_("Options")):
            formatter.write_dl(opts)

def format_epilog(self, ctx: Context, formatter: HelpFormatter) -> None:
    """Writes the epilog into the formatter if it exists."""
    if self.epilog:
        epilog = inspect.cleandoc(self.epilog)
        formatter.write_paragraph()

        with formatter.indentation():
            formatter.write_text(epilog)

def make_context(
    self,
    info_name: str | None,
    args: list[str],
    parent: Context | None = None,
    **extra: t.Any,
) -> Context:
    """This function when given an info name and arguments will kick
    off the parsing and create a new :class:`Context`.  It does not
    invoke the actual command callback though.

    To quickly customize the context class used without overriding
    this method, set the :attr:`context_class` attribute.

    :param info_name: the info name for this invocation.  Generally this
                      is the most descriptive name for the script or
                      command.  For the toplevel script it's usually
                      the name of the script, for commands below it's
                      the name of the command.
    :param args: the arguments to parse as list of strings.
    :param parent: the parent context if available.
    :param extra: extra keyword arguments forwarded to the context
                  constructor.

    .. versionchanged:: 8.0
        Added the :attr:`context_class` attribute.
    """
    for key, value in self.context_settings.items():
        if key not in extra:
            extra[key] = value

    ctx = self.context_class(self, info_name=info_name, parent=parent, **extra)

    with ctx.scope(cleanup=False):
        self.parse_args(ctx, args)
    return ctx

def parse_args(self, ctx: Context, args: list[str]) -> list[str]:
    if not args and self.no_args_is_help and not ctx.resilient_parsing:
        raise NoArgsIsHelpError(ctx)

    parser = self.make_parser(ctx)
    opts, args, param_order = parser.parse_args(args=args)

    for param in iter_params_for_processing(param_order, self.get_params(ctx)):
        value, args = param.handle_parse_result(ctx, opts, args)

    if args and not ctx.allow_extra_args and not ctx.resilient_parsing:
        ctx.fail(
            ngettext(
                "Got unexpected extra argument ({args})",
                "Got unexpected extra arguments ({args})",
                len(args),
            ).format(args=" ".join(map(str, args)))
        )

    ctx.args = args
    ctx._opt_prefixes.update(parser._opt_prefixes)
    return args

def invoke(self, ctx: Context) -> t.Any:
    """Given a context, this invokes the attached callback (if it exists)
    in the right way.
    """
    if self.deprecated:
        extra_message = (
            f" {self.deprecated}" if isinstance(self.deprecated, str) else ""
        )
        message = _(
            "DeprecationWarning: The command {name!r} is deprecated.{extra_message}"
        ).format(name=self.name, extra_message=extra_message)
        echo(style(message, fg="red"), err=True)

    if self.callback is not None:
        return ctx.invoke(self.callback, **ctx.params)

def shell_complete(self, ctx: Context, incomplete: str) -> list[CompletionItem]:
    """Return a list of completions for the incomplete value. Looks
    at the names of options and chained multi-commands.

    Any command could be part of a chained multi-command, so sibling
    commands are valid at any point during command completion.

    :param ctx: Invocation context for this command.
    :param incomplete: Value being completed. May be empty.

    .. versionadded:: 8.0
    """
    from click.shell_completion import CompletionItem

    results: list[CompletionItem] = []

    if incomplete and not incomplete[0].isalnum():
        for param in self.get_params(ctx):
            if (
                not isinstance(param, Option)
                or param.hidden
                or (
                    not param.multiple
                    and ctx.get_parameter_source(param.name)  # type: ignore
                    is ParameterSource.COMMANDLINE
                )
            ):
                continue

            results.extend(
                CompletionItem(name, help=param.help)
                for name in [*param.opts, *param.secondary_opts]
                if name.startswith(incomplete)
            )

    while ctx.parent is not None:
        ctx = ctx.parent

        if isinstance(ctx.command, Group) and ctx.command.chain:
            results.extend(
                CompletionItem(name, help=command.get_short_help_str())
                for name, command in _complete_visible_commands(ctx, incomplete)
                if name not in ctx._protected_args
            )

    return results

